/**
 * univalent-path.ts — HoTT-inspired path types for the Betti compiler.
 *
 * In Homotopy Type Theory (HoTT), equality between two points A and B
 * is not a boolean — it is a topological space of paths connecting them.
 * Multiple proofs of A = B form surfaces; proofs of those proofs form
 * volumes. This scales into ∞-groupoids.
 *
 * This module provides a practical subset of these ideas for the Betti
 * compiler's type system:
 *
 *   1. Path<A, B> — a witnessed equality between two topology states
 *   2. PathComposition — composing paths (transitivity of equality)
 *   3. PathInversion — inverting paths (symmetry of equality)
 *   4. HomotopyLevel — classifying the "depth" of a topology's equality
 *   5. TopologicalHole — detecting homotopy defects in compiled topologies
 *
 * This is NOT a full ∞-topos implementation. It is a principled sketch
 * of how univalent foundations could enrich the Betti compiler's
 * verification, turning structural equivalence into geometric reasoning.
 *
 * The key connection to our existing work:
 *   - The Fibonacci transfer matrix M_n ∈ SL(2,ℤ) IS a path in the
 *     modular group from τ to M_n(τ).
 *   - Composing M_n · M_m = M_{n+m} IS path composition.
 *   - The Cassini determinant = ±1 IS the path's contractibility witness.
 */

// ============================================================================
// Path Types
// ============================================================================

/**
 * A witnessed equality path between two topology states.
 *
 * In standard type theory, equality is a boolean.
 * In HoTT, equality is a space. This type carries the witness.
 */
export interface Path<A, B> {
  /** The source point. */
  readonly source: A;
  /** The target point. */
  readonly target: B;
  /** The witness that source and target are equivalent. */
  readonly witness: string;
  /** The homotopy level of this path (0 = contractible, 1 = path, 2 = surface...). */
  readonly level: number;
}

/**
 * Create a reflexivity path: A = A.
 * The trivial path that stays at a point.
 */
export function refl<A>(point: A): Path<A, A> {
  return {
    source: point,
    target: point,
    witness: 'refl',
    level: 0,
  };
}

/**
 * Create a witnessed path between two states.
 */
export function path<A, B>(
  source: A,
  target: B,
  witness: string
): Path<A, B> {
  return { source, target, witness, level: 1 };
}

/**
 * Compose two paths: if A = B and B = C, then A = C.
 * In HoTT, this is path concatenation.
 */
export function composePaths<A, B, C>(
  p: Path<A, B>,
  q: Path<B, C>
): Path<A, C> {
  return {
    source: p.source,
    target: q.target,
    witness: `${p.witness} · ${q.witness}`,
    level: Math.max(p.level, q.level),
  };
}

/**
 * Invert a path: if A = B, then B = A.
 * In HoTT, this is path inversion.
 */
export function invertPath<A, B>(p: Path<A, B>): Path<B, A> {
  return {
    source: p.target,
    target: p.source,
    witness: `${p.witness}⁻¹`,
    level: p.level,
  };
}

// ============================================================================
// Homotopy Levels (n-truncation)
// ============================================================================

/**
 * The homotopy level classifies how "rich" the equality structure is.
 *
 * Level -2: Contractible (a single point, trivially equal to itself)
 * Level -1: Proposition (at most one proof of equality — mere truth)
 * Level  0: Set (equality is decidable — the boolean world)
 * Level  1: Groupoid (paths between paths matter)
 * Level  2: 2-Groupoid (surfaces between paths matter)
 * Level  n: n-Groupoid (n-dimensional equivalences matter)
 *
 * Our Betti compiler currently operates at Level 0 (Set).
 * The Cassini/KAM/Moonshine proofs are all Level -1 (propositions).
 * A full HoTT upgrade would bring us to Level ≥ 1.
 */
export type HomotopyLevel =
  | 'contractible'  // -2
  | 'proposition'   // -1
  | 'set'           // 0
  | 'groupoid'      // 1
  | '2-groupoid'    // 2
  | 'infinity';     // ∞

/**
 * Handles the gnosis homotopy Level Number workflow.
 */
export function homotopyLevelNumber(level: HomotopyLevel): number {
  switch (level) {
    case 'contractible': return -2;
    case 'proposition': return -1;
    case 'set': return 0;
    case 'groupoid': return 1;
    case '2-groupoid': return 2;
    case 'infinity': return Infinity;
  }
}

// ============================================================================
// Topological Holes — defect detection
// ============================================================================

/**
 * A topological hole in the compiled topology.
 *
 * In HoTT, a bug doesn't manifest as a type error — it manifests as
 * a non-trivial element of a higher homotopy group. A deadlock is a
 * non-contractible loop. A memory leak is a path that doesn't compose
 * back to the identity.
 */
export interface TopologicalHole {
  /** The homotopy group where this defect lives (π_n). */
  readonly homotopyGroup: number;
  /** Human-readable description of the defect. */
  readonly description: string;
  /** The nodes involved in the defective path. */
  readonly involvedNodes: readonly string[];
  /** Can this hole be patched by a homotopy deformation? */
  readonly patchable: boolean;
  /** The suggested patch (a witness that deforms the hole away). */
  readonly suggestedPatch?: string;
}

/**
 * Detect topological holes in a compiled topology.
 *
 * This is a practical subset of homotopy defect detection:
 * - π₁ defects: non-contractible loops (potential deadlocks)
 * - π₀ defects: disconnected components (unreachable code)
 *
 * @param nodes - Map of node IDs to their labels.
 * @param edges - Array of [source, target] pairs.
 */
export function detectTopologicalHoles(
  nodes: Map<string, { labels: string[] }>,
  edges: Array<{ source: string; target: string; type: string }>
): TopologicalHole[] {
  const holes: TopologicalHole[] = [];

  // --- π₀: Disconnected components ---
  // Build adjacency and find connected components.
  const adjacency = new Map<string, Set<string>>();
  for (const [id] of nodes) {
    adjacency.set(id, new Set());
  }
  for (const edge of edges) {
    adjacency.get(edge.source)?.add(edge.target);
    adjacency.get(edge.target)?.add(edge.source);
  }

  const visited = new Set<string>();
  let componentCount = 0;
  const components: string[][] = [];

  for (const [id] of nodes) {
    if (visited.has(id)) continue;
    componentCount++;
    const component: string[] = [];
    const queue = [id];
    while (queue.length > 0) {
      const current = queue.pop()!;
      if (visited.has(current)) continue;
      visited.add(current);
      component.push(current);
      const neighbors = adjacency.get(current);
      if (neighbors) {
        for (const neighbor of neighbors) {
          if (!visited.has(neighbor)) queue.push(neighbor);
        }
      }
    }
    components.push(component);
  }

  if (componentCount > 1) {
    for (let i = 1; i < components.length; i++) {
      const comp = components[i];
      if (comp) {
        holes.push({
          homotopyGroup: 0,
          description: `π₀ defect: disconnected component (${comp.length} nodes unreachable)`,
          involvedNodes: comp,
          patchable: true,
          suggestedPatch: `Add FORK edge from component 0 to node ${comp[0] ?? 'unknown'}`,
        });
      }
    }
  }

  // --- π₁: Non-contractible loops (potential deadlocks) ---
  // Detect cycles where FOLD feeds back into FORK (the cycle detection
  // from handlers.ts, but now classified as a π₁ homotopy defect).
  const forkSources = new Set<string>();
  const foldTargets = new Set<string>();
  for (const edge of edges) {
    if (edge.type === 'FORK') forkSources.add(edge.source);
    if (edge.type === 'FOLD') foldTargets.add(edge.target);
  }

  const feedbackNodes = [...foldTargets].filter((t) => forkSources.has(t));
  if (feedbackNodes.length > 0) {
    holes.push({
      homotopyGroup: 1,
      description: `π₁ defect: ${feedbackNodes.length} FOLD→FORK feedback loop(s) detected`,
      involvedNodes: feedbackNodes,
      patchable: true,
      suggestedPatch:
        'Apply boundary closure (Open → Closed) to upgrade the loop into a KAM-armored torus',
    });
  }

  return holes;
}

// ============================================================================
// Univalent Verification
// ============================================================================

/**
 * A univalent verification result.
 * Combines standard type checking with homotopy defect detection.
 */
export interface UnivalentVerification {
  /** The homotopy level of the compiled topology. */
  readonly homotopyLevel: HomotopyLevel;
  /** Detected topological holes. */
  readonly holes: readonly TopologicalHole[];
  /** Total number of paths (edges) in the topology. */
  readonly pathCount: number;
  /** Total number of points (nodes) in the topology. */
  readonly pointCount: number;
  /** Euler characteristic: points - paths (+ higher cells). */
  readonly eulerCharacteristic: number;
  /** Is the topology homotopically sound? (no non-patchable holes). */
  readonly sound: boolean;
}

/**
 * Perform univalent verification on a compiled topology.
 */
export function verifyUnivalent(
  nodes: Map<string, { labels: string[] }>,
  edges: Array<{ source: string; target: string; type: string }>
): UnivalentVerification {
  const holes = detectTopologicalHoles(nodes, edges);
  const pointCount = nodes.size;
  const pathCount = edges.length;
  const eulerCharacteristic = pointCount - pathCount;

  // Determine homotopy level based on topology structure
  let homotopyLevel: HomotopyLevel;
  if (pointCount === 0) {
    homotopyLevel = 'contractible';
  } else if (holes.length === 0) {
    homotopyLevel = 'set';
  } else if (holes.some((h) => h.homotopyGroup >= 1)) {
    homotopyLevel = 'groupoid';
  } else {
    homotopyLevel = 'proposition';
  }

  const sound = holes.every((h) => h.patchable);

  return {
    homotopyLevel,
    holes,
    pathCount,
    pointCount,
    eulerCharacteristic,
    sound,
  };
}
